```plantuml
@startuml
namespace surcharge {
  namespace seat {
    enum SeatType {
      FreeSeat
      ReservedSeat
    }

    interface Seat {
      +getSeatSurcharge()
    }

    class FreeSeat {
      +Hikari
      +getSeatSurcharge(): Yen
    }

    class ReservedSeat {
      +SuperExpress
      +getSeatSurcharge(): Yen
    }

    SeatType ..|> Seat : createSeat(superExpress: SuperExpress): Seat
    FreeSeat ..|> Seat
    ReservedSeat ..|> Seat
  }

  namespace superexpress {
    enum ShinkansenType {
      Hikari
      Nozomi
    }

    interface SuperExpress {
      +getSuperExpressSurcharge(): Yen
    }

    class Hikari {
      +ShinOsaka
      +Himeji
      +getSuperExpressSurcharge(): Yen
    }

    class Nozomi {
      +ShinOsaka
      +Himeji
      +getSuperExpressSurcharge(): Yen
    }

    ShinkansenType ..|> SuperExpress : createSuperExpress(destination: Destination): SuperExpress
    Hikari ..|> SuperExpress
    Nozomi ..|> SuperExpress
  }

  seat.FreeSeat --> superexpress.Hikari
  seat.ReservedSeat --> superexpress.SuperExpress
}

@enduml
